import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import './StudentAssignmentView.css'; // Vom crea acest CSS

// Interfață pentru o singură temă (bazată pe modelul tău Java)
interface Assignment {
    assid: number;
    asstitle: string;
    description: string;
    createdat: string;
    fileUrl: string; // URL-ul imaginii din Azure
}

const StudentAssignmentView: React.FC = () => {
    const { id } = useParams<{ id: string }>(); // Preluăm ID-ul din URL
    const [assignment, setAssignment] = useState<Assignment | null>(null);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        const fetchAssignment = async () => {
            const token = localStorage.getItem('token');
            try {
                const response = await axios.get<Assignment>(
                    `http://localhost:9090/api/assignments/${id}`,
                    {
                        headers: { Authorization: `Bearer ${token}` }
                    }
                );
                setAssignment(response.data);
            } catch (err) {
                console.error("Eroare la preluarea temei:", err);
                setError("Nu am putut încărca detaliile temei.");
            }
        };

        fetchAssignment();
    }, [id]); // Se re-apelează dacă ID-ul din URL se schimbă

    if (error) {
        return <div className="loading-error">{error}</div>;
    }

    if (!assignment) {
        return <div className="loading-error">Se încarcă tema...</div>;
    }

    return (
        <div className="assignment-view-container">
            {/* Jumătatea din stânga - Imaginea */}
            <div className="image-pane">
                {assignment.fileUrl ? (
                    <img src={assignment.fileUrl} alt="Imaginea temei" />
                ) : (
                    <p>Această temă nu are o imagine atașată.</p>
                )}
            </div>

            {/* Jumătatea din dreapta - Detaliile */}
            <div className="details-pane">
                <h2>{assignment.asstitle}</h2>
                <p className="assignment-date">
                    Primită la: {new Date(assignment.createdat).toLocaleString('ro-RO')}
                </p>

                <h3>Descriere:</h3>
                {/* Folosim 'white-space: pre-wrap' pentru a păstra formatarea (liniile noi) */}
                <p className="assignment-description">
                    {assignment.description}
                </p>

                {/* TODO: Aici poți adăuga formularul de trimitere a temei */}
            </div>
        </div>
    );
};

export default StudentAssignmentView;
